// Pull both forall ensures (one per post-state) into the proof context so
// their triggers line up. Each assert is literally a conjunct of the
// ensures antecedent and is therefore discharged trivially.
assert(forall|p: PagePtr|
    post1_self_.page_is_mapped(p) && p != target_ptr ==>
        post1_self_.page_mappings(p) =~= pre_self_.page_mappings(p)
        && post1_self_.page_io_mappings(p) =~= pre_self_.page_io_mappings(p));
assert(forall|p: PagePtr|
    post2_self_.page_is_mapped(p) && p != target_ptr ==>
        post2_self_.page_mappings(p) =~= pre_self_.page_mappings(p)
        && post2_self_.page_io_mappings(p) =~= pre_self_.page_io_mappings(p));

// Set-valued fields: postN.X =~= pre_self_.X, so post1.X =~= post2.X by
// transitivity of extensional equality.
assert(post1_self_.allocated_pages_4k() =~= post2_self_.allocated_pages_4k());
assert(post1_self_.allocated_pages_2m() =~= post2_self_.allocated_pages_2m());
assert(post1_self_.allocated_pages_1g() =~= post2_self_.allocated_pages_1g());

// Container maps: same chain via pre_self_.container_map_*@.
assert(post1_self_.container_map_4k@ =~= post2_self_.container_map_4k@);
assert(post1_self_.container_map_2m@ =~= post2_self_.container_map_2m@);
assert(post1_self_.container_map_1g@ =~= post2_self_.container_map_1g@);

// target_ptr's mappings: both equal pre_self_.page_mappings(target_ptr).remove((pcid, va))
// and pre_self_.page_io_mappings(target_ptr) respectively.
assert(post1_self_.page_mappings(target_ptr) =~= post2_self_.page_mappings(target_ptr));
assert(post1_self_.page_io_mappings(target_ptr) =~= post2_self_.page_io_mappings(target_ptr));

// Pointwise lift of the page_mappings / page_io_mappings ensures so that
// for every non-target p, the two post-states agree wherever the ensures
// has anything to say (i.e. when the page is mapped under either run).
assert forall|p: PagePtr| p != target_ptr implies
    (post1_self_.page_is_mapped(p) ==>
        post1_self_.page_mappings(p) =~= pre_self_.page_mappings(p)
        && post1_self_.page_io_mappings(p) =~= pre_self_.page_io_mappings(p))
    && (post2_self_.page_is_mapped(p) ==>
        post2_self_.page_mappings(p) =~= pre_self_.page_mappings(p)
        && post2_self_.page_io_mappings(p) =~= pre_self_.page_io_mappings(p)) by {
    // Direct instantiation of the two foralls above at this specific p.
};
